using Microsoft.Data.Sqlite;
using woOshLaundrySystem.Enums;
using woOshLaundrySystem.Models;
namespace woOshLaundrySystem.Data;
public class PackageRepository
{
    public List<LaundryPackagePlan> GetPlans(){var list=new List<LaundryPackagePlan>();using var c=DatabaseHelper.GetConnection();c.Open();using var cmd=c.CreateCommand();cmd.CommandText="SELECT * FROM PackagePlans ORDER BY PackagePlanId";using var r=cmd.ExecuteReader();while(r.Read())list.Add(new LaundryPackagePlan(r.GetInt32(0),r.GetString(1),r.GetInt32(2),r.GetDouble(3),r.GetInt32(4)));return list;}
    public LaundryPackagePlan? GetPlan(int id)=>GetPlans().FirstOrDefault(x=>x.PackagePlanId==id);
    public CustomerPackage? GetActivePackage(int customerId){ExpireOldPackages();using var c=DatabaseHelper.GetConnection();c.Open();using var cmd=c.CreateCommand();cmd.CommandText="SELECT * FROM CustomerPackages WHERE CustomerId=@id AND Status='Active' AND date(EndDate)>=date('now') AND RemainingQuotaKg>0 ORDER BY CustomerPackageId DESC LIMIT 1";cmd.Parameters.AddWithValue("@id",customerId);using var r=cmd.ExecuteReader();return r.Read()?MapPackage(r):null;}
    public int CreateCustomerPackage(int customerId,LaundryPackagePlan plan){var start=DateTime.Now.Date;var end=start.AddDays(plan.DurationDays);using var c=DatabaseHelper.GetConnection();c.Open();using var cmd=c.CreateCommand();cmd.CommandText="INSERT INTO CustomerPackages(CustomerId,PackagePlanId,StartDate,EndDate,InitialQuotaKg,RemainingQuotaKg,Status) VALUES(@c,@p,@s,@e,@i,@r,'Active'); SELECT last_insert_rowid();";cmd.Parameters.AddWithValue("@c",customerId);cmd.Parameters.AddWithValue("@p",plan.PackagePlanId);cmd.Parameters.AddWithValue("@s",start.ToString("yyyy-MM-dd"));cmd.Parameters.AddWithValue("@e",end.ToString("yyyy-MM-dd"));cmd.Parameters.AddWithValue("@i",plan.InitialQuotaKg);cmd.Parameters.AddWithValue("@r",plan.InitialQuotaKg);return Convert.ToInt32(cmd.ExecuteScalar());}
    public void AddPurchase(int customerId,int planId,int pkgId,int amount){using var c=DatabaseHelper.GetConnection();c.Open();using var cmd=c.CreateCommand();cmd.CommandText="INSERT INTO PackagePurchaseTransactions(CustomerId,PackagePlanId,CustomerPackageId,CreatedAt,Amount,PaymentStatus) VALUES(@c,@p,@cp,@d,@a,'Paid')";cmd.Parameters.AddWithValue("@c",customerId);cmd.Parameters.AddWithValue("@p",planId);cmd.Parameters.AddWithValue("@cp",pkgId);cmd.Parameters.AddWithValue("@d",DateTime.Now.ToString("s"));cmd.Parameters.AddWithValue("@a",amount);cmd.ExecuteNonQuery();}
    public void ReduceQuota(int customerPackageId,double weight){using var c=DatabaseHelper.GetConnection();c.Open();using var cmd=c.CreateCommand();cmd.CommandText="UPDATE CustomerPackages SET RemainingQuotaKg=RemainingQuotaKg-@w, Status=CASE WHEN RemainingQuotaKg-@w<=0 THEN 'Expired' ELSE Status END WHERE CustomerPackageId=@id";cmd.Parameters.AddWithValue("@w",weight);cmd.Parameters.AddWithValue("@id",customerPackageId);cmd.ExecuteNonQuery();}
    public void ExpireOldPackages(){using var c=DatabaseHelper.GetConnection();c.Open();using var cmd=c.CreateCommand();cmd.CommandText="UPDATE CustomerPackages SET Status='Expired' WHERE Status='Active' AND (date(EndDate)<date('now') OR RemainingQuotaKg<=0)";cmd.ExecuteNonQuery();}
    CustomerPackage MapPackage(SqliteDataReader r)=>new(){CustomerPackageId=r.GetInt32(0),CustomerId=r.GetInt32(1),PackagePlanId=r.GetInt32(2),Plan=GetPlan(r.GetInt32(2)),StartDate=DateTime.Parse(r.GetString(3)),EndDate=DateTime.Parse(r.GetString(4)),InitialQuotaKg=r.GetDouble(5),RemainingQuotaKg=r.GetDouble(6),Status=Enum.Parse<PackageStatus>(r.GetString(7))};
}